command:
$ErrorActionPreference = 'Stop'
$repo = [Environment]::GetEnvironmentVariable('DCOIR_REPO_ROOT','Machine')
if ([string]::IsNullOrWhiteSpace($repo)) { $repo = (Get-Location).Path }
$script = Join-Path $repo 'operator_tools\github_desktop_lane\scripts\New-DcoirAirtableControlledVocabularyProfile.ps1'
if (-not (Test-Path -LiteralPath $script -PathType Leaf)) { throw ('Missing controlled vocabulary profiler script: ' + $script) }
& $script -OutputNamePrefix 'dcoir_controlled_vocabulary_profile_20260508'
